import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSVulnerableServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Vulnerability: User input is directly echoed back in the response without proper validation or encoding
        response.getWriter().println("<p>User Input: " + userInput + "</p>");
    }
}

